from flask import Flask, request, redirect, url_for, render_template_string
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy database for demonstration purposes
users_db = {
    'user1@example.com': {'mfa_enabled': False}
}

def send_email(to, subject, body):
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = 'no-reply@example.com'
    msg['To'] = to

    with smtplib.SMTP('localhost') as server:
        server.sendmail('no-reply@example.com', [to], msg.as_string())

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form.get('email')
    if email in users_db:
        token = secrets.token_urlsafe()
        reset_link = url_for('reset_mfa', token=token, _external=True)
        send_email(email, 'Enable MFA', f'Click this link to enable MFA: {reset_link}')
        return 'MFA enable request sent. Check your email.'
    else:
        return 'User not found.', 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form.get('email')
    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return 'MFA disabled.'
    else:
        return 'User not found.', 404

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa(token):
    for user_email, user_data in users_db.items():
        if user_data.get('mfa_reset_token') == token:
            user_data['mfa_enabled'] = False
            del user_data['mfa_reset_token']
            return 'MFA disabled. Please log in with your password.'
    return 'Invalid reset link.', 400

if __name__ == '__main__':
    app.run(debug=True)